/**
 * Email Processing Orchestrator
 *
 * Main orchestration service coordinating Gmail API, classification engine,
 * database persistence, and digest generation.
 */

import { ProcessUnclassifiedRequest, ProcessingResult, GmailFetchParams, GmailFetchResult } from './types';

// Basic types for session management (minimal implementation for TDD)
interface SessionListParams {
  limit?: number;
  offset?: number;
  status?: string;
}

interface ClassificationSummary {
  emailId: string;
  status: string;
  confidence: number;
  processingDurationMs: number;
  aiRoutingUsed: boolean;
  primaryCategory?: string;
  error?: string;
}

interface SessionSummary {
  id: string;
  startedAt: string;
  status: string;
  emailCount: number;
  successCount: number;
  errorCount: number;
  avgProcessingTimeMs: number;
}

interface SessionDetails {
  id: string;
  startedAt: string;
  status: string;
  emailCount: number;
  successCount: number;
  errorCount: number;
  processingMode: string;
  batchSize: number;
  performanceMetrics: {
    totalDurationMs: number;
    avgEmailDurationMs: number;
    parallelStagesCount: number;
    databaseBatchOps: number;
    stageTimings: Record<string, unknown>;
    parallelExecutionBreakdown: Record<string, unknown>;
    resourceUsage: {
      maxMemoryMB: number;
      avgCpuPercent: number;
      peakConcurrentOperations: number;
    };
  };
  configVersion: string;
  errors: unknown[];
  warnings: unknown[];
  classifications: ClassificationSummary[];
}

interface SessionListResult {
  sessions: SessionSummary[];
  totalCount: number;
  limit: number;
  offset: number;
  hasMore: boolean;
}

/**
 * Main email processing orchestrator
 */
export class EmailProcessor {
